use ecommerce_project;
select * from ecommerce_sales_dataset;

-- Q1 total records
SELECT COUNT(*) AS total_records
FROM ecommerce_sales_dataset;

-- Q2 total revenue
SELECT SUM(Total_Price) AS total_revenue
FROM ecommerce_sales_dataset;

-- Q3 unique customers
SELECT COUNT(DISTINCT Customer_ID) AS unique_customers
FROM ecommerce_sales_dataset;

-- Q4 Top selling product
select  Product_Name,sum(Quantity) as total_quantity
from ecommerce_sales_dataset
group by Product_Name
order by  total_quantity desc
limit 5;

-- Q5 Total revenue generated by each product category
SELECT 
Product_Category,
ROUND(SUM(Total_Price)/100000, 2) AS revenue_in_lakhs
FROM ecommerce_sales_dataset
GROUP BY Product_Category
ORDER BY revenue_in_lakhs DESC;

-- Q6 Top 5 customers who spent the most money
select Customer_ID,round(sum(Total_price)/100000,2)as total_spend_in_Lakhs
from ecommerce_sales_dataset
group by Customer_ID
order by total_spend_in_Lakhs desc
limit 5;

-- Q7 Number of orders for each payment type
select Payment_Type,count(*) as total_order
from ecommerce_sales_dataset
group by  Payment_Type
order by total_order desc;

-- Q8 Monthly revenue trend
select month(Order_Date) as order_month,round(sum(Total_Price)/100000,2) as monthly_revenue_in_lakhs
from ecommerce_sales_dataset
group by order_month
order by min(order_month);

-- Q9 Cancelled orders
SELECT COUNT(*) AS cancelled_orders
FROM ecommerce_sales_dataset
WHERE Order_Status = 'Cancelled';

-- Q10 Average order value (AOV)
select round(avg(Total_Price),2) as average_order_value
FROM ecommerce_sales_dataset
